+import { PipelineContext, PipelineStep, PipelineConfig } from './types';
+import { logger } from '../../utils/logger';
+
+export class OrderPipeline {
+  private steps: PipelineStep[] = [];
+  private config: PipelineConfig;
+  private completedSteps: PipelineStep[] = [];
+
+  constructor(config: PipelineConfig) {
+    this.config = config;
+    this.steps = config.steps;
+  }
+
+  async execute(orderId: string, userId: string): Promise<PipelineContext> {
+    const ctx: PipelineContext = { orderId, userId, metadata: {} };
+
+    for (const step of this.steps) {
+      try {
+        logger.info(`Executing step: ${step.name}`);
+        const result = await step.execute(ctx);
+        Object.assign(ctx, result);
+        this.completedSteps.push(step);
+      } catch (error) {
+        logger.error(`Step ${step.name} failed:`, error);
+        ctx.error = error as Error;
+        this.config.onError?.(step.name, error as Error, ctx);
+        await this.rollback(ctx);
+        throw error;
+      }
+    }
+
+    return ctx;
+  }
+
+  private async rollback(ctx: PipelineContext): Promise<void> {
+    for (const step of this.completedSteps.reverse()) {
+      try {
+        if (step.rollback) {
+          await step.rollback(ctx);
+        }
+      } catch (rollbackError) {
+        logger.error(`Rollback failed for step ${step.name}:`, rollbackError);
+      }
+    }
+  }
+}

